#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""deploy_sinafix.py — 修新浪兜底 'date' bug + NO_PROXY 环境开关（国内环境优化）

1. api_china.py: 新浪 A 股 qfq 对部分次新股(如 605788)会在 akshare 内部抛
   KeyError 'date' → get_prices 返回空 → current_price=0 → "No valid trade"
   + K线"无数据"。修复: qfq 失败自动降级不复权 + date 索引重置成列。
   另加 AIHF_PRICE_SOURCE=sina 可让新浪优先(海外避免每次等东财超时)。
2. markets/proxy.py: 加 AIHF_NO_PROXY 开关。用国内代理/VPS 时设 AIHF_NO_PROXY=0,
   东财请求走你的代理(不再被 NO_PROXY 强制直连→从海外出口被拒)。

用法: poetry run python deploy_sinafix.py      回滚: deploy_backup/<时间戳>/ 覆盖
"""
import base64, os, sys, shutil
from datetime import datetime

FILES = {
    'src/tools/api_china.py': "",
    'src/markets/proxy.py': "",
}

def main():
    root = os.getcwd()
    if not os.path.isdir(os.path.join(root, "src")):
        print("[FAIL] 请在项目根目录运行"); sys.exit(1)
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    bdir = os.path.join(root, "deploy_backup", ts); os.makedirs(bdir, exist_ok=True)
    for rel, b64 in FILES.items():
        dst = os.path.join(root, *rel.split("/"))
        if os.path.exists(dst):
            shutil.copy2(dst, os.path.join(bdir, rel.replace("/", "__")))
        with open(dst, "wb") as f: f.write(base64.b64decode(b64))
        print(f"[OK] 写入 {rel}")
    print(f"[OK] 备份 -> deploy_backup/{ts}/")
    n=0
    for r,_,_ in os.walk(os.path.join(root,"src")):
        if r.endswith("__pycache__"): shutil.rmtree(r, ignore_errors=True); n+=1
    print(f"[OK] 清理 {n} 个 __pycache__")
    verify(root)

def verify(root):
    print("-"*60); print("验证(复现 605788 故障场景):")
    sys.path.insert(0, root)
    for m in [m for m in list(sys.modules) if "api_china" in m or "markets.proxy" in m]:
        del sys.modules[m]
    try:
        import pandas as pd
        import src.tools.api_china as AC
        class FakeAK:
            def __init__(s): s.calls=[]
            def stock_zh_a_hist(s,**k): s.calls.append("em"); raise Exception("RemoteDisconnected")
            def stock_zh_a_daily(s,symbol,start_date,end_date,adjust=None):
                if adjust=="qfq": raise KeyError("date")
                return pd.DataFrame({"open":[1200.0],"high":[1220.0],"low":[1198.0],
                    "close":[1218.0],"volume":[51000]}, index=pd.Index(["2026-06-19"],name="date"))
        AC._ak=FakeAK(); AC._HAVE_AK=True
        try: AC._cache_v2._prices_cache.clear()
        except Exception: pass
        prices = AC.get_prices("605788.SH","2026-06-01","2026-06-20")
        assert prices and abs(prices[-1].close-1218.0)<1e-6 and prices[-1].time=="2026-06-19"
        print(f"  [PASS] 东财断+新浪qfq抛'date' → 降级raw+date重置 → close={prices[-1].close}")
    except Exception as e:
        import traceback; print(f"  [FAIL] {type(e).__name__}: {e}"); traceback.print_exc(); sys.exit(1)
    try:
        from src.markets import proxy as P
        os.environ["AIHF_NO_PROXY"]="0"; P._ENSURED=False
        os.environ.pop("NO_PROXY",None)
        n,_=P.inject_no_proxy()
        assert n==0
        os.environ["AIHF_NO_PROXY"]="1"; P._ENSURED=False
        n2,_=P.inject_no_proxy(); assert n2>0
        print(f"  [PASS] AIHF_NO_PROXY 开关: =0跳过 / =1注入{n2}hosts")
    except Exception as e:
        print(f"  [FAIL] proxy 开关: {e}"); sys.exit(1)
    print("-"*60)
    print("[SUCCESS] 部署完成 — 重启 web_app 重跑 605788:")
    print("  · current_price 恢复(不再 No valid trade)  · K线出图")
    print("  · 若你用国内代理: 设 AIHF_NO_PROXY=0 让东财走代理 → 板块/资金/财报 agent 可能复活")

if __name__ == "__main__":
    main()
